#include <iostream>

class Point {
private:
    int x;
    int y;

public:
    Point() : x(0), y(0) {}
    Point(int _x, int _y) : x(_x), y(_y) {}
    void displayPoint() {
        std::cout << "Point(" << x << ", " << y << ")" << std::endl;
    }
};

int main() {
    Point p1;
    p1.displayPoint();

    Point p2(5, 10);
    p2.displayPoint();

    Point p3(-3, 7);
    p3.displayPoint();

    return 0;
}
